export interface EmailMessage { id: string; from: string; toLine: string; subject: string; bodyHtml: string; quotedHtml?: string; attachments?: ReadonlyArray<{ name: string; thumbUrl: string }>; receivedAt: number; }
export function EmailThread({ messages }: { messages: ReadonlyArray<EmailMessage> }) {
  const [expandedIds, setExpandedIds] = useState<Set<string>>(new Set([messages[messages.length - 1]?.id ?? '']));
  return (
    <div className="space-y-2">
      {messages.map(m => {
        const isOpen = expandedIds.has(m.id);
        if (!isOpen) return (
          <button key={m.id} type="button" onClick={() => setExpandedIds(s => new Set([...s, m.id]))} className="flex items-center w-full h-9 px-4 text-left text-[13px] bg-[oklch(0.97_0.005_250)] hover:bg-[oklch(0.95_0.005_250)] rounded">
            <span className="font-medium mr-3">{m.from}</span>
            <span className="flex-1 truncate text-[oklch(0.55_0.005_250)]">{m.bodyHtml.replace(/<[^>]*>/g, '').slice(0, 80)}</span>
            <span className="text-[11px] tabular-nums text-[oklch(0.55_0.005_250)] ml-2">{new Date(m.receivedAt).toLocaleDateString()}</span>
          </button>
        );
        return <ExpandedMessage key={m.id} m={m} onCollapse={() => setExpandedIds(s => { const n = new Set(s); n.delete(m.id); return n; })} />;
      })}
    </div>
  );
}
