import { useState, useMemo, useRef } from 'react';
export interface SlashCommand { id: string; name: string; description: string; placeholder?: string; }
export function SlashMenuInput({ commands, onSend, onCommand }: { commands: ReadonlyArray<SlashCommand>; onSend: (text: string) => void; onCommand: (cmd: SlashCommand, args: string) => void }) {
  const [input, setInput] = useState('');
  const [focusIdx, setFocusIdx] = useState(0);
  const isSlash = input.startsWith('/');
  const query = isSlash ? input.slice(1).split(' ')[0] : '';
  const filtered = useMemo(() => isSlash ? commands.filter(c => c.name.startsWith(query)) : [], [commands, isSlash, query]);
  const onKey = (e: React.KeyboardEvent) => {
    if (filtered.length > 0) {
      if (e.key === 'ArrowDown') { e.preventDefault(); setFocusIdx(i => Math.min(filtered.length - 1, i + 1)); }
      else if (e.key === 'ArrowUp') { e.preventDefault(); setFocusIdx(i => Math.max(0, i - 1)); }
      else if (e.key === 'Tab' || e.key === 'Enter') {
        e.preventDefault();
        const cmd = filtered[focusIdx];
        if (e.key === 'Tab') { setInput(`/${cmd.name} `); setFocusIdx(0); }
        else { onCommand(cmd, input.slice(cmd.name.length + 2)); setInput(''); }
      }
      else if (e.key === 'Escape') { /* keeps input */ }
    } else if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      if (input.trim()) { onSend(input); setInput(''); }
    }
  };
  return (
    <div className="relative">
      <textarea value={input} onChange={(e) => { setInput(e.target.value); setFocusIdx(0); }} onKeyDown={onKey} placeholder="Type / for commands" className="w-full min-h-12 p-3 text-[14px] border border-[oklch(0.85_0.005_250)] rounded-md outline-none focus:border-[oklch(0.55_0.18_250)] resize-none" />
      {filtered.length > 0 && (
        <div className="absolute bottom-full mb-1 left-0 w-80 bg-[oklch(0.18_0.005_250)] text-white rounded-md shadow-lg overflow-hidden" style={{ animation: 'slashIn 80ms ease-out' }}>
          {filtered.map((c, i) => (
            <div key={c.id} className={`px-3 py-2 text-[13px] cursor-pointer ${i === focusIdx ? 'bg-[oklch(0.28_0.005_250)]' : ''}`} onClick={() => { onCommand(c, ''); setInput(''); }}>
              <span className="font-mono">/{c.name}</span>
              <span className="text-[11px] opacity-70 ml-2">{c.description}</span>
            </div>
          ))}
          <style>{`@keyframes slashIn { from { opacity: 0 } to { opacity: 1 } }`}</style>
        </div>
      )}
    </div>
  );
}

