import { useState } from 'react';
export function StarRating({ value, max = 5, onChange, precision = 0.5 }: { value: number; max?: number; onChange: (v: number) => void; precision?: 0.5 | 1 }) {
  const [hoverValue, setHoverValue] = useState<number | null>(null);
  const displayValue = hoverValue ?? value;
  const onMove = (e: React.MouseEvent, idx: number) => {
    const r = (e.currentTarget as HTMLButtonElement).getBoundingClientRect();
    const pct = (e.clientX - r.left) / r.width;
    const half = pct < 0.5 ? 0.5 : 1;
    const v = precision === 0.5 ? idx + half : idx + 1;
    setHoverValue(v);
  };
  return (
    <div className="flex gap-0.5" role="radiogroup" aria-label="Rating">
      {Array.from({ length: max }).map((_, i) => {
        const fillPct = Math.max(0, Math.min(1, displayValue - i)) * 100;
        return (
          <button key={i} type="button" role="radio" aria-checked={value === i + 1 || value === i + 0.5} aria-label={`${i + 1} stars`} onMouseMove={(e) => onMove(e, i)} onMouseLeave={() => setHoverValue(null)} onClick={() => onChange(hoverValue ?? value)} className="relative w-5 h-5">
            <svg viewBox="0 0 20 20" className="absolute inset-0"><path d="M10 1 L12 7 L19 7.5 L13.5 12 L15.5 19 L10 15 L4.5 19 L6.5 12 L1 7.5 L8 7 Z" fill="oklch(0.88 0.005 250)" /></svg>
            <svg viewBox="0 0 20 20" className="absolute inset-0" style={{ clipPath: `inset(0 ${100 - fillPct}% 0 0)` }}><path d="M10 1 L12 7 L19 7.5 L13.5 12 L15.5 19 L10 15 L4.5 19 L6.5 12 L1 7.5 L8 7 Z" fill="oklch(0.8 0.18 80)" /></svg>
          </button>
        );
      })}
    </div>
  );
}

