import { useState, useEffect, useRef, Children, cloneElement } from 'react';
const KEY = 'first-time-hint-v1';
export function FirstTimeHint({ id, hint, successesNeeded = 3, children }: { id: string; hint: string; successesNeeded?: number; children: React.ReactNode }) {
  const [successes, setSuccesses] = useState<number>(() => { try { return JSON.parse(localStorage.getItem(KEY) ?? '{}')[id] ?? 0; } catch { return 0; } });
  const [hovered, setHovered] = useState(false);
  const isDismissed = successes >= successesNeeded;
  const recordSuccess = () => {
    const next = successes + 1;
    setSuccesses(next);
    try { const all = JSON.parse(localStorage.getItem(KEY) ?? '{}'); all[id] = next; localStorage.setItem(KEY, JSON.stringify(all)); } catch {}
  };
  return (
    <div onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)} onClick={recordSuccess}>
      {children}
      {!isDismissed && hovered && <div className="mt-1 text-[11px] italic text-[oklch(0.55_0.005_250)]" style={{ animation: 'hintIn 200ms ease-out' }}>{hint}</div>}
      <style>{`@keyframes hintIn { from { opacity: 0 } to { opacity: 1 } } @media (prefers-reduced-motion: reduce) { [style*='hintIn'] { animation: none !important } }`}</style>
    </div>
  );
}

