export function Globe({ arcs }: { arcs: ReadonlyArray<{ fromLatLng: [number, number]; toLatLng: [number, number] }> }) {
  const ref = useRef<Mesh>(null);
  useFrame((_, dt) => { if (ref.current) ref.current.rotation.y += 0.1 * dt; });
  return (
