  return (
    <div className="group relative my-2 px-3 py-2 hover:bg-[oklch(0.97_0.005_250)]" onTouchStart={modality === 'touch' ? onTouchStart : undefined} onTouchEnd={modality === 'touch' ? onTouchEnd : undefined}>
