export function jitteredRect(w: number, h: number, jitter = 2): string {
  const j = () => (Math.random() - 0.5) * jitter;
  return `M${j()},${j()} L${w + j()},${j()} L${w + j()},${h + j()} L${j()},${h + j()} Z`;
}
