import { useState, useMemo } from 'react';
export interface Notification { id: string; source: string; sourceColor: string; title: string; body: string; createdAt: number; read: boolean; }
export function NotificationCenter({ notifications, onAction }: { notifications: ReadonlyArray<Notification>; onAction: (id: string, action: 'read' | 'archive' | 'mute') => void }) {
  const grouped = useMemo(() => { const m = new Map<string, Notification[]>(); for (const n of notifications) { if (!m.has(n.source)) m.set(n.source, []); m.get(n.source)!.push(n); } return m; }, [notifications]);
  const [collapsed, setCollapsed] = useState<Set<string>>(new Set());
  return (
    <div>{Array.from(grouped.entries()).map(([source, items]) => { const unread = items.filter(i => !i.read).length; const isCollapsed = collapsed.has(source); return (
      <section key={source} className="mb-3">
        <header className="flex items-center justify-between px-3 py-2 bg-[oklch(0.97_0.005_250)] rounded-t">
          <button type="button" onClick={() => setCollapsed(c => { const n = new Set(c); if (n.has(source)) n.delete(source); else n.add(source); return n; })} className="flex items-center gap-2 text-[13px] font-medium">
            <span style={{ color: items[0].sourceColor }}>{isCollapsed ? '\u25B8' : '\u25BE'}</span>{source} {unread > 0 && <span className="px-1.5 py-0.5 text-[10px] bg-[oklch(0.55_0.18_250)] text-white rounded">{unread}</span>}
          </button>
          <button type="button" onClick={() => items.forEach(i => onAction(i.id, 'read'))} className="text-[11px] text-[oklch(0.55_0.005_250)]">Mark all read</button>
        </header>
        {!isCollapsed && <ul>{items.map(n => (
          <li key={n.id} className="flex items-start gap-3 px-3 py-2 border-b border-[oklch(0.95_0.005_250)]">
            {!n.read && <span className="w-1.5 h-1.5 rounded-full bg-[oklch(0.55_0.18_250)] mt-1.5" />}
            <div className="flex-1"><div className="text-[13px] font-medium">{n.title}</div><div className="text-[12px] text-[oklch(0.55_0.005_250)]">{n.body}</div></div>
            <span className="text-[11px] tabular-nums text-[oklch(0.55_0.005_250)]">{new Date(n.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
          </li>
        ))}</ul>}
      </section>
    ); })}</div>
  );
}

import { useEffect } from 'react';
export function useAppShortcuts(handlers: { onSettings?: () => void; onCommandPalette?: () => void; onSearch?: () => void; onHelp?: () => void }) {
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (!(e.metaKey || e.ctrlKey)) return;
      if (e.key === ',' && handlers.onSettings) { e.preventDefault(); handlers.onSettings(); }
      else if (e.key === 'k' && handlers.onCommandPalette) { e.preventDefault(); handlers.onCommandPalette(); }
      else if (e.key === 'l' && handlers.onSearch) { e.preventDefault(); handlers.onSearch(); }
      else if (e.key === '/' && handlers.onHelp) { e.preventDefault(); handlers.onHelp(); }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [handlers]);
}
// Usage: useAppShortcuts({ onSettings: () => navigate('/settings'), onCommandPalette: () => setPaletteOpen(true) });

export interface Typer { userId: string; userName: string; lastKeystrokeAt: number; }
export function TypingIndicators({ typers }: { typers: ReadonlyArray<Typer> }) {
  const active = typers.filter(t => Date.now() - t.lastKeystrokeAt < 3000);
  if (active.length === 0) return null;
  let label = '';
  if (active.length === 1) label = `${active[0].userName} is typing`;
  else if (active.length === 2) label = `${active[0].userName} and ${active[1].userName} are typing`;
  else label = 'Several people are typing';
