import { useState, useRef } from 'react';
export function SwipeActionRow({ children, onArchive, onDelete }: { children: React.ReactNode; onArchive: () => void; onDelete: () => void }) {
  const [offset, setOffset] = useState(0);
  const startX = useRef(0);
  const onTouchStart = (e: React.TouchEvent) => { startX.current = e.touches[0].clientX; };
  const onTouchMove = (e: React.TouchEvent) => { const dx = e.touches[0].clientX - startX.current; setOffset(Math.max(-300, Math.min(0, dx))); if (Math.abs(dx) === 160) navigator.vibrate?.(8); };
  const onTouchEnd = () => { if (offset < -160) { setOffset(-280); if (confirm('Delete this item?')) onDelete(); else setOffset(0); } else if (offset < -60) { onArchive(); setOffset(0); } else setOffset(0); };
  const isDestructiveZone = offset < -160;
  return (
    <div className="relative overflow-hidden">
      <div className="absolute inset-y-0 right-0 flex items-center justify-end px-4 text-white text-[14px] font-medium" style={{ background: isDestructiveZone ? 'oklch(0.6 0.18 25)' : 'oklch(0.75 0.16 145)' }}>{isDestructiveZone ? 'Delete' : 'Archive'}</div>
      <div onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd} className="relative bg-white" style={{ transform: `translateX(${offset}px)`, transition: startX.current && offset !== 0 ? 'none' : 'transform 200ms ease-out' }}>{children}</div>
    </div>
  );
}

import { useMemo } from 'react';
export interface ParetoItem { label: string; value: number; }
export function ParetoChart({ items }: { items: ReadonlyArray<ParetoItem> }) {
  const W = 600, H = 320, PAD = 40;
  const sorted = useMemo(() => [...items].sort((a, b) => b.value - a.value), [items]);
  const total = sorted.reduce((s, x) => s + x.value, 0);
  const max = sorted[0]?.value ?? 1;
  const cumulative: number[] = []; let acc = 0; for (const i of sorted) { acc += i.value; cumulative.push(acc / total); }
  const bw = (W - 2 * PAD) / sorted.length - 4;
  const linePath = cumulative.map((c, i) => `${i ? 'L' : 'M'}${(PAD + i * (bw + 4) + bw / 2).toFixed(1)} ${(H - PAD - c * (H - 2 * PAD)).toFixed(1)}`).join(' ');
  return (
    <svg width={W} height={H}>
      <line x1={PAD} y1={H - PAD - 0.8 * (H - 2 * PAD)} x2={W - PAD} y2={H - PAD - 0.8 * (H - 2 * PAD)} stroke="oklch(0.55 0.005 250)" strokeDasharray="4 4" strokeWidth="1" />
      <text x={W - PAD} y={H - PAD - 0.8 * (H - 2 * PAD) - 4} fontSize="10" textAnchor="end" fill="oklch(0.55 0.005 250)">80%</text>
      {sorted.map((it, i) => { const h = (it.value / max) * (H - 2 * PAD); return <rect key={i} x={PAD + i * (bw + 4)} y={H - PAD - h} width={bw} height={h} fill="oklch(0.55 0.18 250)" />; })}
      <path d={linePath} stroke="oklch(0.55 0.18 25)" strokeWidth="2" fill="none" />
      {cumulative.map((c, i) => <circle key={i} cx={PAD + i * (bw + 4) + bw / 2} cy={H - PAD - c * (H - 2 * PAD)} r={3} fill="oklch(0.55 0.18 25)" />)}
    </svg>
  );
}

