export function relativeLuminance(rgb: [number, number, number]): number {
  const [r, g, b] = rgb.map(c => { c /= 255; return c <= 0.03928 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4); });
  return 0.2126 * r + 0.7152 * g + 0.0722 * b;
}
export function contrastRatio(fg: [number, number, number], bg: [number, number, number]): number {
  const lf = relativeLuminance(fg), lb = relativeLuminance(bg);
  const lighter = Math.max(lf, lb), darker = Math.min(lf, lb);
  return (lighter + 0.05) / (darker + 0.05);
}
export function wcagLevel(ratio: number): { normalAA: boolean; normalAAA: boolean; largeAA: boolean; largeAAA: boolean } {
  return { normalAA: ratio >= 4.5, normalAAA: ratio >= 7, largeAA: ratio >= 3, largeAAA: ratio >= 4.5 };
}
// ContrastPair.tsx
export function ContrastPair({ fg, bg, label }: { fg: [number, number, number]; bg: [number, number, number]; label: string }) {
  const ratio = contrastRatio(fg, bg);
  const w = wcagLevel(ratio);
  const fgCss = `rgb(${fg.join(',')})`, bgCss = `rgb(${bg.join(',')})`;
  return (
    <div className="border border-[oklch(0.92_0.005_250)] rounded p-3">
      <div className="h-16 rounded flex items-center justify-center text-[16px] font-medium" style={{ background: bgCss, color: fgCss }}>{label}</div>
      <div className="mt-2 flex items-baseline justify-between">
        <span className="text-[14px] tabular-nums font-medium">{ratio.toFixed(2)}:1</span>
        <div className="flex gap-1 text-[10px] uppercase">
          {(['normalAA','normalAAA','largeAA','largeAAA'] as const).map(k => <span key={k} className={`px-1.5 py-0.5 rounded ${w[k] ? 'bg-[oklch(0.94_0.06_145)] text-[oklch(0.4_0.14_145)]' : 'bg-[oklch(0.95_0.04_25)] text-[oklch(0.4_0.16_25)]'}`}>{k.replace(/normal|large/, m => m === 'normal' ? 'N' : 'L').replace(/AA(?!A)/, ' AA').replace(/AAA/, ' AAA')}</span>)}
        </div>
      </div>
    </div>
  );
}

