import { useState, useCallback } from 'react';
export function useMultiSelect<T extends { id: string }>(items: ReadonlyArray<T>) {
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [anchor, setAnchor] = useState<string | null>(null);
  const onClick = useCallback((id: string, e: React.MouseEvent) => {
    if (e.shiftKey && anchor) {
      const ai = items.findIndex(i => i.id === anchor);
      const ci = items.findIndex(i => i.id === id);
      if (ai >= 0 && ci >= 0) { const [lo, hi] = ai < ci ? [ai, ci] : [ci, ai]; setSelected(new Set(items.slice(lo, hi + 1).map(i => i.id))); }
    } else if (e.metaKey || e.ctrlKey) {
      setSelected(s => { const n = new Set(s); if (n.has(id)) n.delete(id); else n.add(id); return n; });
      setAnchor(id);
    } else {
      setSelected(new Set([id]));
      setAnchor(id);
    }
  }, [items, anchor]);
  const selectAll = useCallback(() => { setSelected(new Set(items.map(i => i.id))); }, [items]);
  const clear = useCallback(() => setSelected(new Set()), []);
  return { selected, onClick, selectAll, clear };
}

