import { useCallback, useEffect, useRef, useState } from 'react';
export type SaveState = 'saved' | 'editing' | 'saving' | 'error';
export function useSaveState<T>(value: T, save: (v: T) => Promise<void>, debounceMs = 1500) {
  const [state, setState] = useState<SaveState>('saved');
  const [lastSavedAt, setLastSavedAt] = useState(Date.now());
  const timerRef = useRef<number | null>(null);
  const lastSavedValue = useRef(value);
  useEffect(() => {
    if (value === lastSavedValue.current) return;
    setState('editing');
    if (timerRef.current) window.clearTimeout(timerRef.current);
    timerRef.current = window.setTimeout(async () => {
      setState('saving');
      try { await save(value); lastSavedValue.current = value; setLastSavedAt(Date.now()); setState('saved'); } catch { setState('error'); }
    }, debounceMs);
  }, [value, save, debounceMs]);
  return { state, lastSavedAt };
}
// SaveIndicator.tsx
export function SaveIndicator({ state, lastSavedAt }: { state: SaveState; lastSavedAt: number }) {
  const relTime = Math.floor((Date.now() - lastSavedAt) / 1000);
  const text = state === 'saved' ? `Saved \u00B7 ${relTime < 60 ? `${relTime}s` : `${Math.floor(relTime / 60)}m`} ago` : state === 'editing' ? 'Editing\u2026' : state === 'saving' ? 'Saving\u2026' : 'Failed to save';
  const color = state === 'error' ? 'oklch(0.55 0.18 25)' : state === 'saving' ? 'oklch(0.55 0.18 250)' : 'oklch(0.55 0.005 250)';
  return <span role="status" aria-live="polite" className="text-[11px]" style={{ color, transition: 'color 100ms ease-out' }}>{text}</span>;
}

import { useState } from 'react';
export function Histogram({ bins, onBrush }: { bins: ReadonlyArray<{ label: string; count: number }>; onBrush: (range: [number, number] | null) => void }) {
  const W = 480, H = 120;
  const max = Math.max(...bins.map(b => b.count), 1);
  const bw = W / bins.length;
  const [brushRange, setBrushRange] = useState<[number, number] | null>(null);
  const onMouseDown = (e: React.MouseEvent<SVGElement>) => {
    const r = e.currentTarget.getBoundingClientRect();
    const start = Math.floor((e.clientX - r.left) / bw);
    const onMove = (ev: MouseEvent) => { const end = Math.floor((ev.clientX - r.left) / bw); const range: [number, number] = [Math.min(start, end), Math.max(start, end)]; setBrushRange(range); onBrush(range); };
    const onUp = () => { document.removeEventListener('mousemove', onMove); document.removeEventListener('mouseup', onUp); };
    document.addEventListener('mousemove', onMove);
    document.addEventListener('mouseup', onUp);
  };
  return (
    <svg width={W} height={H} onMouseDown={onMouseDown} className="cursor-crosshair">
      {bins.map((b, i) => { const h = (b.count / max) * (H - 8); const inBrush = brushRange && i >= brushRange[0] && i <= brushRange[1]; return <rect key={i} x={i * bw + 1} y={H - h} width={bw - 2} height={h} fill="oklch(0.55 0.18 250)" style={{ opacity: brushRange ? (inBrush ? 1 : 0.3) : 1 }} />; })}
    </svg>
  );
}

